// Collect emails and calendar events from parallel branches
const config = $('2. Set — Config Values').item.json;

// Process emails
let emailItems = [];
try {
  const gmailItems = $('3. Gmail — Fetch Unread Emails').all();
  emailItems = gmailItems.map(item => {
    const msg = item.json;
    return {
      from: msg.from || 'Unknown sender',
      subject: msg.subject || 'No subject',
      date: msg.date || '',
      snippet: (msg.snippet || '').substring(0, 200)
    };
  });
} catch (e) {
  emailItems = [];
}

// Process calendar events
let calendarItems = [];
try {
  const calItems = $('4. Google Calendar — Fetch Today and Tomorrow').all();
  calendarItems = calItems.map(item => {
    const event = item.json;
    const startTime = event.start?.dateTime || event.start?.date || '';
    const endTime = event.end?.dateTime || event.end?.date || '';
    let timeDisplay = 'All day';
    if (event.start?.dateTime) {
      const start = new Date(event.start.dateTime);
      const end = new Date(event.end?.dateTime || event.start.dateTime);
      timeDisplay =
        start.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) +
        ' to ' +
        end.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
    }
    const eventDate = new Date(startTime);
    const today = new Date();
    const isToday = eventDate.toDateString() === today.toDateString();
    const tomorrow = new Date(today);
    tomorrow.setDate(today.getDate() + 1);
    const isTomorrow = eventDate.toDateString() === tomorrow.toDateString();
    return {
      title: event.summary || 'Untitled event',
      time: timeDisplay,
      location: event.location || '',
      attendees: (event.attendees || []).length,
      isToday,
      isTomorrow
    };
  });
} catch (e) {
  calendarItems = [];
}

const todayEvents = calendarItems.filter(e => e.isToday);
const tomorrowEvents = calendarItems.filter(e => e.isTomorrow);

// Format emails for GPT
let emailText = 'No unread emails in the last 24 hours.';
if (emailItems.length > 0) {
  emailText = emailItems.slice(0, 20).map((e, i) =>
    (i + 1) + '. From: ' + e.from + '\n   Subject: ' + e.subject + '\n   Preview: ' + e.snippet
  ).join('\n\n');
}

// Format today events for GPT
let todayText = 'No events scheduled for today.';
if (todayEvents.length > 0) {
  todayText = todayEvents.map((e, i) =>
    (i + 1) + '. ' + e.title + ' — ' + e.time +
    (e.location ? ' — ' + e.location : '') +
    (e.attendees > 0 ? ' (' + e.attendees + ' attendees)' : '')
  ).join('\n');
}

// Format tomorrow events for GPT
let tomorrowText = 'No events scheduled for tomorrow.';
if (tomorrowEvents.length > 0) {
  tomorrowText = tomorrowEvents.map((e, i) =>
    (i + 1) + '. ' + e.title + ' — ' + e.time +
    (e.location ? ' — ' + e.location : '') +
    (e.attendees > 0 ? ' (' + e.attendees + ' attendees)' : '')
  ).join('\n');
}

return [{
  json: {
    emailText,
    todayText,
    tomorrowText,
    totalEmails: emailItems.length,
    totalTodayEvents: todayEvents.length,
    totalTomorrowEvents: tomorrowEvents.length,
    todayFormatted: config.todayFormatted,
    companyName: config.companyName,
    telegramChatId: config.telegramChatId
  }
}];

// Get the brief text from GPT output
const briefText = $input.first().json.output || 'Good morning! Your brief could not be generated today. Please check your credentials.';
const config = $('2. Set — Config Values').item.json;

// Add a timestamp footer
const timeNow = new Date().toLocaleTimeString('en-GB', {
  hour: '2-digit',
  minute: '2-digit',
  timeZone: config.timezone || 'UTC'
});

const fullMessage = briefText + '\n\n_Brief generated at ' + timeNow + ' — powered by n8n_';

return [{
  json: {
    telegramMessage: fullMessage,
    telegramChatId: config.telegramChatId
  }
}];
